CREATE TABLE discovery_leads (id UUID DEFAULT gen_random_uuid() PRIMARY KEY, type TEXT NOT NULL CHECK (type IN ('festival', 'popup_spot')), name TEXT NOT NULL, url TEXT UNIQUE NOT NULL, emails TEXT[], vibe_score INTEGER CHECK (vibe_score >= 1 AND vibe_score <= 100), vibe_notes TEXT, status TEXT NOT NULL DEFAULT 'PENDING' CHECK (status IN ('PENDING', 'CONTACTED', 'INTERESTED', 'REJECTED')), source TEXT NOT NULL CHECK (source IN ('cron', 'manual')), created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL);
